const fs = require('fs');
const path = require('path');
const mysql = require('mysql2/promise');

// Cargar variables de entorno del archivo .env en la raíz
const envPath = path.join(__dirname, '../.env');
if (!fs.existsSync(envPath)) {
  console.error('\x1b[31mError: No se encontró el archivo .env en la raíz del proyecto.\x1b[0m');
  process.exit(1);
}
require('dotenv').config({ path: envPath });

const { DB_HOST, DB_PORT, DB_USER, DB_PASSWORD, DB_NAME } = process.env;

// Directorio de uploads en el backend
const uploadsDir = path.join(__dirname, '../backend/uploads');

// Imágenes base64 mínimas y válidas para evitar imágenes rotas en el primer arranque
// 1. Un logo representativo verde-azul para REASONS (PNG válido de 48x48)
const logoBase64 = '';

// 2. Un avatar de usuario por defecto gris (PNG de 48x48)
const avatarBase64 = '';

// 3. Una portada de proyecto por defecto (PNG 100x75)
const projectBase64 = '';

// 4. Una portada de revista científica por defecto (PNG 75x100)
const journalBase64 = '';

// Verificar que existe la carpeta uploads
if (!fs.existsSync(uploadsDir)) {
  fs.mkdirSync(uploadsDir, { recursive: true });
  console.log('Creada la carpeta backend/uploads.');
}

// Escribir las imágenes por defecto
fs.writeFileSync(path.join(uploadsDir, 'logo_reasons.png'), Buffer.from(logoBase64, 'base64'));
fs.writeFileSync(path.join(uploadsDir, 'default_avatar.png'), Buffer.from(avatarBase64, 'base64'));
fs.writeFileSync(path.join(uploadsDir, 'default_project.png'), Buffer.from(projectBase64, 'base64'));
fs.writeFileSync(path.join(uploadsDir, 'default_journal.png'), Buffer.from(journalBase64, 'base64'));

console.log('\x1b[32m✔ Se han generado correctamente las imágenes semilla en backend/uploads.\x1b[0m');

async function seedDatabase() {
  console.log('Conectando a MySQL para verificar los datos de las tablas...');

  let connection;
  try {
    connection = await mysql.createConnection({
      host: DB_HOST || 'localhost',
      port: DB_PORT || 3306,
      user: DB_USER || 'root',
      password: DB_PASSWORD || '',
      database: DB_NAME || 'reasons_db'
    });

    // 1. Validar si ya hay configuraciones
    const [settings] = await connection.query('SELECT COUNT(*) as count FROM site_settings');
    if (settings[0].count === 0) {
      console.log('Poblando tabla site_settings...');
      await connection.query(`
        INSERT INTO site_settings (id, logo_url, group_name, institution, description, objective_general, mission, vision, primary_color, secondary_color, accent_color, contact_address, contact_location, contact_email)
        VALUES (
          1, 
          'uploads/logo_reasons.png', 
          'REASONS', 
          'Universidad Técnica de Ambato',
          'Grupo de investigación que impulsa soluciones innovadoras en ingeniería con un enfoque de sostenibilidad y compromiso social.',
          'Desarrollar investigación aplicada e interdisciplinaria en el campo de la ingeniería.',
          'Generar conocimiento científico y aplicado en el área de ingeniería mediante proyectos éticos de alto impacto, contribuyendo activamente al desarrollo sostenible y al bienestar de la sociedad.',
          'Ser reconocidos a nivel nacional e internacional como un grupo de investigación referente en sostenibilidad y tecnologías avanzadas de ingeniería para el año 2030.',
          '#0A5C36', 
          '#F4A261', 
          '#1D3557', 
          'Av. de Los Chasquis y Av. Río Payamino. Facultad de Ingeniería en Sistemas, Electrónica e Industrial.',
          'Universidad Técnica de Ambato. Ambato – Ecuador.',
          'reasons@uta.edu.ec'
        )
      `);
      console.log('✔ site_settings poblado.');
    } else {
      console.log('✔ La tabla site_settings ya contiene información.');
    }

    // 2. Validar objetivos específicos
    const [objs] = await connection.query('SELECT COUNT(*) as count FROM specific_objectives');
    if (objs[0].count === 0) {
      console.log('Poblando tabla specific_objectives...');
      await connection.query(`
        INSERT INTO specific_objectives (settings_id, objective, order_index) VALUES 
        (1, 'Diseñar y optimizar procesos en ingeniería con criterios de sostenibilidad.', 1),
        (1, 'Generar proyectos de investigación científica orientados a resolver problemáticas regionales y globales.', 2),
        (1, 'Formar profesionales e investigadores con una visión ética, ambiental y social sólida.', 3)
      `);
      console.log('✔ specific_objectives poblado.');
    } else {
      console.log('✔ La tabla specific_objectives ya contiene información.');
    }

    // 3. Validar líneas de investigación
    const [lines] = await connection.query('SELECT COUNT(*) as count FROM research_lines');
    if (lines[0].count === 0) {
      console.log('Poblando tabla research_lines...');
      await connection.query(`
        INSERT INTO research_lines (settings_id, title, description, icon, order_index) VALUES 
        (1, 'Diseño, Materiales, Producción, Identidad, Sostenibilidad y Tecnologías aplicadas', 'Enfoque en la creación de productos ecológicos, análisis del ciclo de vida, optimización de materiales e innovaciones en procesos productivos industriales.', 'bi-palette', 1),
        (1, 'Software, Tecnologías de la Información y Ciencias de Datos', 'Desarrollo de sistemas de información inteligentes, análisis predictivos usando Big Data, soluciones móviles y automatización aplicada a la resolución de problemas científicos y sociales.', 'bi-code-slash', 2),
        (1, 'Energía, Desarrollo Sostenible y Gestión de Recursos Naturales', 'Estudio de energías renovables, mitigación de la huella de carbono, optimización del recurso hídrico y conservación ambiental a través de la ingeniería.', 'bi-globe-americas', 3)
      `);
      console.log('✔ research_lines pobladas.');
    } else {
      console.log('✔ La tabla research_lines ya contiene información.');
    }

    // 4. Validar usuario administrador
    const [users] = await connection.query('SELECT COUNT(*) as count FROM users');
    if (users[0].count === 0) {
      console.log('Poblando tabla de usuarios con administrador por defecto...');
      await connection.query(`
        INSERT INTO users (username, password_hash, role) 
        VALUES ('admin', '$2a$12$gpIJHgGk8ZTetRfIsnigFOOR.y6rf6U0D9fpIRP/gHKjT/C2TuQx.', 'admin')
      `);
      console.log('✔ Usuario administrador "admin" creado con contraseña por defecto.');
    } else {
      console.log('✔ La tabla users ya contiene administradores.');
    }

    // 5. Validar carrusel de diapositivas del Hero
    const [slides] = await connection.query('SELECT COUNT(*) as count FROM hero_slides');
    if (slides[0].count === 0) {
      console.log('Poblando tabla hero_slides con diapositivas semilla...');
      await connection.query(`
        INSERT INTO hero_slides (image_url, title, subtitle, order_index) VALUES 
        ('uploads/hero_reasons.png', 'Investigación Científica con Impacto Real', 'Desarrollamos soluciones tecnológicas aplicadas para resolver los desafíos más exigentes de la industria moderna.', 1),
        ('uploads/sustainability_research.png', 'Compromiso con el Desarrollo Sostenible', 'Promovemos proyectos que cuidan el medio ambiente, optimizan los recursos hídricos y potencian las energías limpias.', 2),
        ('uploads/team_collaboration.png', 'Trabajo Colaborativo e Interdisciplinario', 'Impulsamos la sinergia científica uniendo investigadores altamente calificados para crear un futuro sostenible.', 3)
      `);
      console.log('✔ Diapositivas semilla creadas exitosamente.');
    } else {
      console.log('✔ La tabla hero_slides ya contiene diapositivas.');
    }

    console.log('\x1b[32m==================================================\x1b[0m');
    console.log('\x1b[32m✔ ¡BASE DE DATOS POBLADA EXITOSAMENTE CON SEMILLAS! \x1b[0m');
    console.log('\x1b[32m==================================================\x1b[0m');

  } catch (err) {
    console.error('\x1b[31m✖ ERROR AL POBLAR LA BASE DE DATOS:\x1b[0m');
    console.error(err.message);
    process.exit(1);
  } finally {
    if (connection) {
      await connection.end();
    }
  }
}

seedDatabase();
